# Data Model

class UrlSpec:
    """
    Container for a URL template. Use {from_year} and {to_year} placeholders
    where the numbers should go in the query string.
    """
    __slots__ = ("url_template",)

    def __init__(self, url_template: str = ""):
        self.url_template = url_template

    def materialize(self, from_year: int, to_year: int) -> str:
        """
        Replace {from_year}/{to_year} if present; if missing, append them.
        """
        if "{from_year}" in self.url_template or "{to_year}" in self.url_template:
            return self.url_template.format(from_year=from_year, to_year=to_year)
        joiner = "&" if "?" in self.url_template else "?"
        return f"{self.url_template}{joiner}fromYear={from_year}&toYear={to_year}"


def default_to_year() -> int:
    # WIPO site usually lags; default to current_year - 2
    #return dt.date.today().year - 2

    # adjust the default date thorugh this or you can ovveride it using this command: i.e python -m country_profile.cli fetch-wipo --root . --from-year 1980 --to-year 2023 --overwrite --max-workers 8

    return 2024


