# http helpers

def _make_session() -> requests.Session:
    s = requests.Session()
    retry = Retry(
        total=8, connect=6, read=6,
        backoff_factor=0.8,
        status_forcelist=[429, 500, 502, 503, 504],
        allowed_methods=["GET"],
        raise_on_status=False,
    )
    adapter = HTTPAdapter(max_retries=retry, pool_connections=32, pool_maxsize=64)
    s.mount("https://", adapter)
    s.headers.update({
        "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome",
        "Origin": "https://www3.wipo.int",
        "Referer": "https://cdn.ipstatsdc.deda.prd.web1.wipo.int/",
        "Accept": "text/csv,application/octet-stream,*/*;q=0.1",
        "Accept-Language": "en-US,en;q=0.9",
        "Cache-Control": "no-cache",
    })
    return s


def _prime_cookies(session: requests.Session) -> None:
    # Touch UI pages to receive public cookies used by the API gateway
    for path in (
        "https://cdn.ipstatsdc.deda.prd.web1.wipo.int/ipstats/ips-search/patent",
        "https://cdn.ipstatsdc.deda.prd.web1.wipo.int/ipstats/ips-search/trademark",
    ):
        try:
            session.get(path, timeout=30)
        except Exception:
            pass


def _safe_name(name: str) -> str:
    # conservative: strip characters illegal on Windows/macOS
    return "".join(ch for ch in name if ch not in '<>:"/\\|?*').strip()


# Download Logic

def _download_one(
    session: requests.Session,
    key: str,
    spec: UrlSpec,
    out_dir: Path,
    from_year: int,
    to_year: int,
    overwrite: bool,
) -> Optional[Path]:
    if not spec.url_template:
        logger.info("Skip (blank): %s", key)
        return None

    url = spec.materialize(from_year, to_year)

    # Save as <KEY>_<from>_<to>.csv
    fname = _safe_name(f"{key}_{from_year}_{to_year}.csv")
    fpath = out_dir / fname

    if fpath.exists() and not overwrite and fpath.stat().st_size > 0:
        logger.info("Skip (exists): %s", fname)
        return fpath

    with session.get(url, timeout=300, stream=True) as r:
        if r.status_code == 400:
            # Retry once with an explicit CSV hint
            try_url = url + ("&downloadType=CSV" if "?" in url else "?downloadType=CSV")
            r.close()
            r = session.get(try_url, timeout=300, stream=True)

        if r.status_code != 200:
            raise RuntimeError(f"HTTP {r.status_code} for {fname}: {r.text[:200]}")

        tmp = fpath.with_suffix(fpath.suffix + ".part")
        with open(tmp, "wb") as f:
            for chunk in r.iter_content(chunk_size=1 << 20):
                if chunk:
                    f.write(chunk)
        if tmp.stat().st_size == 0:
            tmp.unlink(missing_ok=True)
            raise RuntimeError(f"Empty download for {fname}")
        tmp.replace(fpath)

    logger.info("Wrote %s (%s bytes)", fname, fpath.stat().st_size)
    return fpath


def fetch_all(
    paths: DataPaths,
    from_year: int = 1980,
    to_year: Optional[int] = None,
    overwrite: bool = False,
    max_workers: int = min(8, os.cpu_count() or 4),
) -> List[Path]:
    """
    Download every entry whose URL template is filled in `URLS`.
    Years are injected via {from_year}/{to_year}. Output: <KEY>_<from>_<to>.csv
    """
    if to_year is None:
        to_year = default_to_year()

    out_dir = paths.raw_ip_indicators
    out_dir.mkdir(parents=True, exist_ok=True)

    session = _make_session()
    _prime_cookies(session)

    written: List[Path] = []
    errors: List[str] = []

    with ThreadPoolExecutor(max_workers=max_workers) as ex:
        futs = [
            ex.submit(_download_one, session, key, spec, out_dir, from_year, to_year, overwrite)
            for key, spec in URLS.items()
        ]
        for fut in as_completed(futs):
            try:
                p = fut.result()
                if p:
                    written.append(p)
            except Exception as e:
                logger.error("Download failed: %s", e)
                errors.append(str(e))

    filled_count = sum(1 for spec in URLS.values() if spec.url_template)
    logger.info("[bold]Done:[/bold] %d/%d files → %s", len(written), filled_count, out_dir)
    if errors:
        logger.warning("Some files failed (%d):\n- %s", len(errors), "\n- ".join(errors))
    return written

