# Override the previously-defined _download_one with a filename-aware version.
# (Python uses the last definition; no need to edit earlier code.)
if _USE_ORIGINAL_FILENAMES:
    _prev__download_one = _download_one  # keep a reference just in case

    def _download_one(
        session: requests.Session,
        key: str,
        spec: UrlSpec,
        out_dir: Path,
        from_year: int,
        to_year: int,
        overwrite: bool,
    ) -> Optional[Path]:
        if not spec.url_template:
            logger.info("Skip (blank): %s", key)
            return None

        url = spec.materialize(from_year, to_year)

        # Use original long filename when available, else fallback to short KEY name
        tmpl = _ORIGINAL_FILENAME_TEMPLATES.get(key)
        if tmpl:
            fname = _safe_name(tmpl.format(from_year=from_year, to_year=to_year))
        else:
            fname = _safe_name(f"{key}_{from_year}_{to_year}.csv")

        fpath = out_dir / fname
        if fpath.exists() and not overwrite and fpath.stat().st_size > 0:
            logger.info("Skip (exists): %s", fname)
            return fpath

        with session.get(url, timeout=300, stream=True) as r:
            if r.status_code == 400:
                try_url = url + ("&downloadType=CSV" if "?" in url else "?downloadType=CSV")
                r.close()
                r = session.get(try_url, timeout=300, stream=True)

            if r.status_code != 200:
                raise RuntimeError(f"HTTP {r.status_code} for {fname}: {r.text[:200]}")

            tmp = fpath.with_suffix(fpath.suffix + ".part")
            with open(tmp, "wb") as f:
                for chunk in r.iter_content(chunk_size=1 << 20):
                    if chunk:
                        f.write(chunk)
            if tmp.stat().st_size == 0:
                tmp.unlink(missing_ok=True)
                raise RuntimeError(f"Empty download for {fname}")
            tmp.replace(fpath)

        logger.info("Wrote %s (%s bytes)", fname, fpath.stat().st_size)
        return fpath

